487	bool moveRight(uint8_t board[SIZE][SIZE], uint32_t *score)
488	{
489		bool success;
490		rotateBoard(board);
491		rotateBoard(board);
492		rotateBoard(board);
493		success = moveUp(board, score);
494		rotateBoard(board);
495		return success;
496	}
