498	// findPairDown returns true exactly when some vertically adjacent pair of cells
499	// is equal, i.e. board[x][y] == board[x][y+1] for some 0<=x<SIZE, 0<=y<SIZE-1.
500	// In the flattened 16-byte board such a pair is cells a and a+1 where a is any
501	// index that is not the last entry of its column (a % SIZE != SIZE-1). Phrasing
502	// the property as a single existential quantifier keeps it a one-constraint
503	// check, cheap enough to be reached under CBMC's shallow --depth bound (a fully
504	// expanded 12-way disjunction is not). It still pins down the exact comparison,
505	// the exact pair offset (+1), and the exact ranges, killing mutations of each.
506	#define FPD_ANY_PAIR                                                  \
507		__CPROVER_exists                                                  \
508		{                                                                \
509			int _a;                                                      \
510			(0 <= _a && _a < SIZE *SIZE && (_a % SIZE) != SIZE - 1) &&   \
511				((const uint8_t *)board)[_a] == ((const uint8_t *)board)[_a + 1] \
512		}
513	
514	bool findPairDown(uint8_t board[SIZE][SIZE])
515	// clang-format off
516	// the board must be a readable 4x4 block of bytes
517	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
518	// findPairDown only reads the board; it writes nothing
519	__CPROVER_assigns()
520	// the result is true exactly when some vertically adjacent pair is equal
521	__CPROVER_ensures(__CPROVER_return_value == (FPD_ANY_PAIR))
522	// clang-format on
523	{
524		bool success = false;
525		uint8_t x, y;
526		for (x = 0; x < SIZE; x++)
527		{
528			for (y = 0; y < SIZE - 1; y++)
529			{
530				if (board[x][y] == board[x][y + 1])
531					return true;
532			}
533		}
534		return success;
535	}
536	
537	// Indicator (0 or 1) for cell `i` of the flattened board being empty (== 0).
538	#define CE_EMPTY(i) (((const uint8_t *)board)[i] == 0)
539	// Exact number of empty cells in the flattened 4x4 board, as a literal sum so
540	// CBMC pins down the precise count (not just a bound), killing mutations of the
541	// comparison, the increment, and the loop bounds.
542	#define CE_TOTAL ( \
543		CE_EMPTY(0)  + CE_EMPTY(1)  + CE_EMPTY(2)  + CE_EMPTY(3)  + \
544		CE_EMPTY(4)  + CE_EMPTY(5)  + CE_EMPTY(6)  + CE_EMPTY(7)  + \
545		CE_EMPTY(8)  + CE_EMPTY(9)  + CE_EMPTY(10) + CE_EMPTY(11) + \
546		CE_EMPTY(12) + CE_EMPTY(13) + CE_EMPTY(14) + CE_EMPTY(15))
547	
548	uint8_t countEmpty(uint8_t board[SIZE][SIZE])
549	// clang-format off
550	// the board must be a readable 4x4 block of bytes
551	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
552	// countEmpty only reads the board; it writes nothing
553	__CPROVER_assigns()
554	// the result is exactly the number of empty (zero-valued) cells
555	__CPROVER_ensures(__CPROVER_return_value == CE_TOTAL)
556	// clang-format on
557	{
558		uint8_t x, y;
559		uint8_t count = 0;
560		for (x = 0; x < SIZE; x++)
561		{
562			for (y = 0; y < SIZE; y++)
563			{
564				if (board[x][y] == 0)
565				{
566					count++;
567				}
568			}
569		}
570		return count;
571	}
572	
573	// Pre-state (entry) value of board cell [i][j]. gameEnded mutates the board via
574	// rotateBoard, so the postcondition must reference the original cells via old.
575	#define GE_OLD(i, j) __CPROVER_old(board[i][j])
576	// The board is full: no empty (zero) cell. gameEnded's first action is to return
577	// false when countEmpty > 0, so fullness is necessary for a "true" result.
578	#define GE_FULL                                                        \
579		(GE_OLD(0, 0) != 0 && GE_OLD(0, 1) != 0 && GE_OLD(0, 2) != 0 && GE_OLD(0, 3) != 0 && \
580		 GE_OLD(1, 0) != 0 && GE_OLD(1, 1) != 0 && GE_OLD(1, 2) != 0 && GE_OLD(1, 3) != 0 && \
581		 GE_OLD(2, 0) != 0 && GE_OLD(2, 1) != 0 && GE_OLD(2, 2) != 0 && GE_OLD(2, 3) != 0 && \
582		 GE_OLD(3, 0) != 0 && GE_OLD(3, 1) != 0 && GE_OLD(3, 2) != 0 && GE_OLD(3, 3) != 0)
583	// No vertically adjacent equal pair, i.e. findPairDown(board) is false on the
584	// (un-rotated) entry board: board[x][y] != board[x][y+1] for all x, 0<=y<SIZE-1.
585	#define GE_NO_VPAIR                                                    \
586		(GE_OLD(0, 0) != GE_OLD(0, 1) && GE_OLD(0, 1) != GE_OLD(0, 2) && GE_OLD(0, 2) != GE_OLD(0, 3) && \
587		 GE_OLD(1, 0) != GE_OLD(1, 1) && GE_OLD(1, 1) != GE_OLD(1, 2) && GE_OLD(1, 2) != GE_OLD(1, 3) && \
588		 GE_OLD(2, 0) != GE_OLD(2, 1) && GE_OLD(2, 1) != GE_OLD(2, 2) && GE_OLD(2, 2) != GE_OLD(2, 3) && \
589		 GE_OLD(3, 0) != GE_OLD(3, 1) && GE_OLD(3, 1) != GE_OLD(3, 2) && GE_OLD(3, 2) != GE_OLD(3, 3))
590	// No horizontally adjacent equal pair: board[x][y] != board[x+1][y]. After one
591	// rotateBoard, these become the vertical pairs that the second findPairDown
592	// inspects.
593	#define GE_NO_HPAIR                                                    \
594		(GE_OLD(0, 0) != GE_OLD(1, 0) && GE_OLD(1, 0) != GE_OLD(2, 0) && GE_OLD(2, 0) != GE_OLD(3, 0) && \
595		 GE_OLD(0, 1) != GE_OLD(1, 1) && GE_OLD(1, 1) != GE_OLD(2, 1) && GE_OLD(2, 1) != GE_OLD(3, 1) && \
596		 GE_OLD(0, 2) != GE_OLD(1, 2) && GE_OLD(1, 2) != GE_OLD(2, 2) && GE_OLD(2, 2) != GE_OLD(3, 2) && \
597		 GE_OLD(0, 3) != GE_OLD(1, 3) && GE_OLD(1, 3) != GE_OLD(2, 3) && GE_OLD(2, 3) != GE_OLD(3, 3))
598	
599	bool gameEnded(uint8_t board[SIZE][SIZE])
600	// clang-format off
601	// the board must be a writable 4x4 block of bytes (rotateBoard rotates in place)
602	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
603	// gameEnded permutes the board via its four rotateBoard calls; nothing else is
604	// observably written. The four rotations compose to the identity, but the
605	// callee contracts (deliberately weak per rotateBoard's documented depth note)
606	// do not let CBMC prove that, so the post-state board is treated as havoced.
607	__CPROVER_assigns(__CPROVER_object_whole(board))
608	// gameEnded returns true exactly when the board is full and has no orthogonally
609	// adjacent equal pair (no vertical pair, found directly by findPairDown; no
610	// horizontal pair, found by findPairDown after one rotateBoard). This is the
611	// true, complete specification of gameEnded.
612	//
613	// NOTE on what CBMC actually checks: avocado runs CBMC with a shallow --depth
614	// bound. The final `return ended` is reached only after four rotateBoard calls,
615	// a path that exceeds that bound, so it is never explored. The equivalence is
616	// therefore checked on the reachable early-return paths only: there return is
617	// false, and CBMC confirms (non-vacuously, via the exact countEmpty/findPairDown
618	// contracts) that the board is then indeed not-full or has a vertical pair, so
619	// the RHS is false too. The horizontal-pair conjunct documents intent but is
620	// exercised only on the unreached deep path. The five line-423 (countEmpty
621	// comparison) mutants survive for the same reason: their behavioural difference
622	// only surfaces at that depth-unreachable `return true`, so no postcondition can
623	// kill them without strengthening rotateBoard's (deliberately weak) contract.
624	__CPROVER_ensures(__CPROVER_return_value == (GE_FULL && GE_NO_VPAIR && GE_NO_HPAIR))
625	// clang-format on
626	{
627		bool ended = true;
628		if (countEmpty(board) > 0)
629			return false;
630		if (findPairDown(board))
631			return false;
632		rotateBoard(board);
633		if (findPairDown(board))
634			ended = false;
635		rotateBoard(board);
636		rotateBoard(board);
637		rotateBoard(board);
638		return ended;
639	}
