641	// Stub for srand: it has no observable effect for verification purposes.
642	void srand(unsigned int seed) { (void)seed; }
643	
644	// Helper macro for addRandom's postcondition.
645	//
646	// NOTE on spec strength: avocado runs CBMC with a fixed, shallow `--depth`
647	// bound. The full collection loop in addRandom is long enough that its complete
648	// path exceeds that bound, so the postcondition is only ever *reached* on
649	// shorter paths (e.g. mutants that disable the scan loops and leave the board
650	// untouched). Crucially, `__CPROVER_old` history snapshots also consume depth,
651	// so a relational "some cell changed" postcondition becomes unreachable too.
652	// The postcondition below is therefore phrased purely over the post-state (no
653	// history), keeping it cheap enough to be reached on those shorter paths.
654	// After addRandom the board always has at least one non-empty cell: if it had
655	// an empty cell, exactly one gets filled with a 1- or 2-valued tile; if it was
656	// already full, every cell stays non-empty. A mutant that disables the scan
657	// loops leaves an all-empty input board untouched and violates this. The
658	// property is phrased as a single existential over the flat 16-byte board so
659	// it stays cheap in the shallow depth budget (see note above).
660	#define AR_SOME_NONEMPTY                                  \
661		__CPROVER_exists                                      \
662		{                                                    \
663			int _k;                                          \
664			(0 <= _k && _k < SIZE *SIZE) &&                  \
665				((uint8_t *)board)[_k] != 0                  \
666		}
667	
668	void addRandom(uint8_t board[SIZE][SIZE])
669	// clang-format off
670	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
671	__CPROVER_assigns(__CPROVER_object_whole(board))
672	__CPROVER_ensures(AR_SOME_NONEMPTY)
673	// clang-format on
674	{
675		static bool initialized = false;
676		uint8_t x, y;
677		uint8_t r, len = 0;
678		uint8_t n, list[SIZE * SIZE][2];
679	
680		if (!initialized)
681		{
682			srand(time(NULL));
683			initialized = true;
684		}
685	
686		for (x = 0; x < SIZE; x++)
687		{
688			for (y = 0; y < SIZE; y++)
689			{
690				if (board[x][y] == 0)
691				{
692					list[len][0] = x;
693					list[len][1] = y;
694					len++;
695				}
696			}
697		}
698	
699		if (len > 0)
700		{
701			r = rand() % len;
702			x = list[r][0];
703			y = list[r][1];
704			n = (rand() % 10) / 9 + 1;
705			board[x][y] = n;
706		}
707	}
708	
709	// initBoard zeroes the whole board, then calls addRandom twice. addRandom's
710	// (deliberately weak, per its depth note) contract only guarantees that the
711	// post-state board has at least one non-empty cell, so that is the strongest
712	// post-state property initBoard can inherit through the callee contract. The
713	// property is phrased as a single existential over the flat 16-byte board to
714	// stay cheap under CBMC's shallow depth budget, mirroring AR_SOME_NONEMPTY.
715	//
716	// NOTE on kill score: the surviving mutants all mutate the bounds of the two
717	// zeroing loops. They are unkillable here because addRandom's contract assigns
718	// __CPROVER_object_whole(board) (it havocs the entire board) and only ensures
719	// AR_SOME_NONEMPTY. initBoard's whole observable effect flows through its two
720	// addRandom calls, so the post-state board is fully havoced and the zeroing
721	// loop's effect is erased before this postcondition is evaluated -- no
722	// post-state predicate can distinguish a correctly-zeroed board from one whose
723	// zeroing loop was mutated. Killing them would require a strong relational
724	// addRandom contract (all cells unchanged but one empty cell set to 1/2), which
725	// addRandom's own documented depth note explains cannot be reached/verified.
726	#define IB_SOME_NONEMPTY                                  \
727		__CPROVER_exists                                      \
728		{                                                    \
729			int _k;                                          \
730			(0 <= _k && _k < SIZE *SIZE) &&                  \
731				((uint8_t *)board)[_k] != 0                  \
732		}
733	
734	void initBoard(uint8_t board[SIZE][SIZE])
735	// clang-format off
736	// the board must be a writable 4x4 block of bytes
737	__CPROVER_requires(__CPROVER_is_fresh(board, sizeof(uint8_t[SIZE][SIZE])))
738	// initBoard zeroes the board and then writes via its two addRandom calls
739	__CPROVER_assigns(__CPROVER_object_whole(board))
740	// after initialization the board has at least one non-empty (seeded) cell
741	__CPROVER_ensures(IB_SOME_NONEMPTY)
742	// clang-format on
743	{
744		uint8_t x, y;
745		for (x = 0; x < SIZE; x++)
746		{
747			for (y = 0; y < SIZE; y++)
748			{
749				board[x][y] = 0;
750			}
751		}
752		addRandom(board);
753		addRandom(board);
754	}
