756	void setBufferedInput(bool enable)
757	{
758		static bool enabled = true;
759		static struct termios old;
760		struct termios new;
761	
762		if (enable && !enabled)
763		{
764			// restore the former settings
765			tcsetattr(STDIN_FILENO, TCSANOW, &old);
766			// set the new state
767			enabled = true;
768		}
769		else if (!enable && enabled)
770		{
771			// get the terminal settings for standard input
772			tcgetattr(STDIN_FILENO, &new);
773			// we want to keep the old setting to restore them at the end
774			old = new;
775			// disable canonical mode (buffered i/o) and local echo
776			new.c_lflag &= (~ICANON & ~ECHO);
777			// set the new settings immediately
778			tcsetattr(STDIN_FILENO, TCSANOW, &new);
779			// set the new state
780			enabled = false;
781		}
782	}
