784	bool testSucceed()
785	{
786		uint8_t array[SIZE];
787		// these are exponents with base 2 (1=2 2=4 3=8)
788		// data holds per line: 4x IN, 4x OUT, 1x POINTS
789		uint8_t data[] = {
790			0, 0, 0, 1, 1, 0, 0, 0, 0,
791			0, 0, 1, 1, 2, 0, 0, 0, 4,
792			0, 1, 0, 1, 2, 0, 0, 0, 4,
793			1, 0, 0, 1, 2, 0, 0, 0, 4,
794			1, 0, 1, 0, 2, 0, 0, 0, 4,
795			1, 1, 1, 0, 2, 1, 0, 0, 4,
796			1, 0, 1, 1, 2, 1, 0, 0, 4,
797			1, 1, 0, 1, 2, 1, 0, 0, 4,
798			1, 1, 1, 1, 2, 2, 0, 0, 8,
799			2, 2, 1, 1, 3, 2, 0, 0, 12,
800			1, 1, 2, 2, 2, 3, 0, 0, 12,
801			3, 0, 1, 1, 3, 2, 0, 0, 4,
802			2, 0, 1, 1, 2, 2, 0, 0, 4};
803		uint8_t *in, *out, *points;
804		uint8_t t, tests;
805		uint8_t i;
806		bool success = true;
807		uint32_t score;
808	
809		tests = (sizeof(data) / sizeof(data[0])) / (2 * SIZE + 1);
810		for (t = 0; t < tests; t++)
811		{
812			in = data + t * (2 * SIZE + 1);
813			out = in + SIZE;
814			points = in + 2 * SIZE;
815			for (i = 0; i < SIZE; i++)
816			{
817				array[i] = in[i];
818			}
819			score = 0;
820			slideArray(array, &score);
821			for (i = 0; i < SIZE; i++)
822			{
823				if (array[i] != out[i])
824				{
825					success = false;
826				}
827			}
828			if (score != *points)
829			{
830				success = false;
831			}
832			if (success == false)
833			{
834				for (i = 0; i < SIZE; i++)
835				{
836					printf("%u ", in[i]);
837				}
838				printf("=> ");
839				for (i = 0; i < SIZE; i++)
840				{
841					printf("%u ", array[i]);
842				}
843				printf("(%u points) expected ", score);
844				for (i = 0; i < SIZE; i++)
845				{
846					printf("%u ", in[i]);
847				}
848				printf("=> ");
849				for (i = 0; i < SIZE; i++)
850				{
851					printf("%u ", out[i]);
852				}
853				printf("(%u points)\n", *points);
854				break;
855			}
856		}
857		if (success)
858		{
859			printf("All %u tests executed successfully\n", tests);
860		}
861		return success;
862	}
