883		{
884			if (strcmp(argv[1], "-h") == 0 || strcmp(argv[1], "--help") == 0)
885			{
886				printf("Usage: 2048 [OPTION] | [MODE]\n");
887				printf("Play the game 2048 in the console\n\n");
888				printf("Options:\n");
