890				printf("  -v,  --version    Show version number.\n\n");
891				printf("Modes:\n");
892				printf("  bluered      Use a blue-to-red color scheme (requires 256-color terminal support).\n");
893				printf("  blackwhite   The black-to-white color scheme (requires 256-color terminal support).\n");
894				return EXIT_SUCCESS;
895			}
896			else if (strcmp(argv[1], "-v") == 0 || strcmp(argv[1], "--version") == 0)
897			{
898				printf("2048.c version %s\n", VERSION);
899				return EXIT_SUCCESS;
900			}
901			else if (strcmp(argv[1], "blackwhite") == 0)
902			{
903				scheme = 1;
904			}
905			else if (strcmp(argv[1], "bluered") == 0)
906			{
907				scheme = 2;
908			}
909			else if (strcmp(argv[1], "whiteblack") == 0)
910			{
911				scheme = 3;
912			}
913			else if (strcmp(argv[1], "test") == 0)
914			{
915				return testSucceed() ? EXIT_SUCCESS : EXIT_FAILURE;
916			}
917			else
918			{
919				printf("Invalid option: %s\n\nTry '%s --help' for more options.\n", argv[1], argv[0]);
920				return EXIT_FAILURE;
921			}
922		}
923	
924		// make cursor invisible, erase entire screen
925		printf("\033[?25l\033[2J");
926	
927		// register signal handler for when ctrl-c is pressed
928		signal(SIGINT, signal_callback_handler);
929	
930		initBoard(board);
931		setBufferedInput(false);
932		drawBoard(board, scheme, score);
933		while (true)
934		{
935			c = getchar();
936			if (c == EOF)
937			{
938				puts("\nError! Cannot read keyboard input!");
939				break;
940			}
941			switch (c)
942			{
943			case 52:  // '4' key
944			case 97:  // 'a' key
945			case 104: // 'h' key
946			case 68:  // left arrow
947				success = moveLeft(board, &score);
948				break;
949			case 54:  // '6' key
950			case 100: // 'd' key
