954				break;
955			case 56:  // '8' key
956			case 119: // 'w' key
957			case 107: // 'k' key
958			case 65:  // up arrow
959				success = moveUp(board, &score);
960				break;
961			case 50:  // '2' key
962			case 115: // 's' key
963			case 106: // 'j' key
964			case 66:  // down arrow
965				success = moveDown(board, &score);
