981			}
982			if (c == 'q')
983			{
984				printf("        QUIT? (y/n)         \n");
985				c = getchar();
986				if (c == 'y')
987				{
988					break;
989				}
990				drawBoard(board, scheme, score);
991			}
992			if (c == 'r')
993			{
994				printf("       RESTART? (y/n)       \n");
995				c = getchar();
996				if (c == 'y')
997				{
998					initBoard(board);
999					score = 0;
1000				}
1001				drawBoard(board, scheme, score);
1002			}
1003		}
1004		setBufferedInput(true);
1005	
1006		// make cursor visible, reset all modes
1007		printf("\033[?25h\033[m");
1008	
1009		return EXIT_SUCCESS;
1010	}
